import{_ as a,a as o,b as s}from"./chunks/支持留言.NiGCLVdp.js";import{_ as i,o as t,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Como usar o blog","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Other/blog.md","filePath":"pt-BR/Other/blog.md","lastUpdated":1781962217000}'),d={name:"pt-BR/Other/blog.md"};function l(n,e,c,g,u,m){return t(),r("div",null,[...e[0]||(e[0]=[p('<h1 id="como-usar-o-blog" tabindex="-1">Como usar o blog <a class="header-anchor" href="#como-usar-o-blog" aria-label="Permalink to &quot;Como usar o blog&quot;">​</a></h1><p>O recurso de blog adiciona uma página de blog independente ao seu site ImgBed.</p><p>Depois de ativado, os visitantes podem acessar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://seu-dominio/blog/</span></span></code></pre></div><p><img src="'+a+'" alt="Página inicial do blog" loading="lazy"></p><p>O blog foi adaptado do projeto open source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. O ImgBed reescreve e integra a experiência em Vue para ela funcionar dentro do site de hospedagem.</p><h2 id="onde-configurar" tabindex="-1">Onde configurar <a class="header-anchor" href="#onde-configurar" aria-label="Permalink to &quot;Onde configurar&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configurações do sistema -&gt; Outras configurações -&gt; Blog</span></span></code></pre></div><p><img src="'+o+'" alt="Configurações do blog" loading="lazy"></p><h2 id="primeiro-uso" tabindex="-1">Primeiro uso <a class="header-anchor" href="#primeiro-uso" aria-label="Permalink to &quot;Primeiro uso&quot;">​</a></h2><ol><li>Ative a opção <code>Habilitar</code>.</li><li>Escolha a conta do GitHub que vai guardar as configurações do blog.</li><li>Clique em <code>Atualizar blog</code>.</li><li>Aguarde a mensagem de sucesso.</li><li>Abra <code>https://seu-dominio/blog/</code> para conferir.</li></ol><p>Na primeira utilização, o ImgBed prepara um repositório privado na conta do GitHub escolhida:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Esse repositório guarda as configurações do blog e o conteúdo dos posts.</p><h2 id="como-escrever-posts" tabindex="-1">Como escrever posts <a class="header-anchor" href="#como-escrever-posts" aria-label="Permalink to &quot;Como escrever posts&quot;">​</a></h2><p>Os posts são editados no seu repositório privado do GitHub:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Fluxo comum:</p><ol><li>Abra o GitHub.</li><li>Entre no repositório <code>imgbed-blog-config</code>.</li><li>Crie ou edite arquivos de posts.</li><li>Faça commit das alterações.</li><li>Volte ao painel do ImgBed e clique em <code>Atualizar blog</code>. Também dá para clicar três vezes no logotipo no canto superior esquerdo do blog para disparar a atualização.</li></ol><p><code>Atualizar blog</code> não sobrescreve posts que você já escreveu. A função serve principalmente para inicializar o repositório ou atualizar o cache do blog.</p><h2 id="recursos-disponiveis" tabindex="-1">Recursos disponíveis <a class="header-anchor" href="#recursos-disponiveis" aria-label="Permalink to &quot;Recursos disponíveis&quot;">​</a></h2><p>O blog oferece lista de posts, categorias, tags, arquivo, busca, modo escuro e troca de idioma.</p><p>Também há suporte a comentários e estatísticas de visitas.</p><p><img src="'+s+'" alt="Comentários do blog" loading="lazy"></p><p>Os comentários aparecem abaixo do post. O visitante pode informar avatar, apelido, e-mail e o conteúdo do comentário.</p><p>As estatísticas mostram visualizações de posts e visitas ao site, ajudando a acompanhar o tráfego do blog.</p><h2 id="endereco-de-acesso" tabindex="-1">Endereço de acesso <a class="header-anchor" href="#endereco-de-acesso" aria-label="Permalink to &quot;Endereço de acesso&quot;">​</a></h2><p>O blog sempre fica no caminho <code>/blog/</code>.</p><p>Se o domínio do seu ImgBed for:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>o endereço do blog será:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Ao desativar o blog, visitantes deixam de acessar essa página.</p>',33)])])}const f=i(d,[["render",l]]);export{v as __pageData,f as default};
